def somar_lote(valores):
    total = 0
    for valor in valores:
        total += valor
    return total

print(somar_lote([10, 20, 30]))

def contar_ate_sentinela(valores, marcador):
    i = 0
    while i < len(valores) and valores[i] != marcador:
        i += 1
    return i

print(contar_ate_sentinela([4, 5, 0, 9], 0))

def resumo_alertas(valores, limite):
    soma = 0
    qtd = 0
    for valor in valores:
        soma += valor
        if valor >= limite:
            qtd += 1
    return soma, qtd

soma, qtd = resumo_alertas([12, 80, 51, 9], 50)
print(soma, qtd)
